// // This module performs a bitwise OR operation between the negation of 'r' and 'a', and assigns the result to 'out'. The output 'out_r' is the logical AND of 'r' and 'a'.
module top_module(a,r,out,out_r);input wire a,r;
output wire out, out_r;

assign  out = (~r)&&a; 
assign  out_r = r||a;

endmodule
